mapper.select:
select d.deceased_id, d.org_id, d.family_user_id, d.name, d.gender, d.birth_date, d.death_date,
       d.cemetery_area, d.cemetery_number, d.bio, d.cover_image, d.qrcode_code, d.qrcode_url,
       d.is_public, d.allow_message, d.message_audit, d.status, d.del_flag, d.remark,
       d.create_by, d.create_time, d.update_by, d.update_time, o.org_name
from mem_deceased d
left join mem_organization o on d.org_id = o.org_id
where d.del_flag = '0'

    and d.name like concat('%', #{name}, '%')


    and d.org_id = #{orgId}


    and d.family_user_id = #{familyUserId}


    and d.qrcode_code = #{qrcodeCode}


    and d.status = #{status}

order by d.create_time desc
